public class Main {
    static void combinationSum(int[] candidates, int target, int start, List<Integer> current, List<List<Integer>> result) {
        if (target == 0) {
            result.add(new ArrayList<>(current));
            return;
        }
        if (target < 0) {
            return; // PRUNE -- this path can never work, stop exploring it
        }

        for (int i = start; i < candidates.length; i++) {
            current.add(candidates[i]);
            combinationSum(candidates, target - candidates[i], i, current, result);
            current.remove(current.size() - 1);
        }
    }

    public static void main(String[] args) {
        int[] candidates = {2, 3, 5};
        List<List<Integer>> result = new ArrayList<>();
        combinationSum(candidates, 7, 0, new ArrayList<>(), result);
        System.out.println(result);
    }
