class Solution {
    public java.util.List<String> letterCombinations(String digits) {
        if (digits.isEmpty()) return new java.util.ArrayList<>();
        String[] mapping = {"", "", "abc", "def", "ghi", "jkl", "mno", "pqrs", "tuv", "wxyz"};

        java.util.List<String> result = new java.util.ArrayList<>();
        result.add("");
        for (char digit : digits.toCharArray()) {
            java.util.List<String> next = new java.util.ArrayList<>();
            String letters = mapping[digit - '0'];
            for (String prefix : result) {
                for (char letter : letters.toCharArray()) {
                    next.add(prefix + letter);
                }
            }
            result = next;
        }
        return result;
    }
}

class Solution {
    private final String[] mapping = {"", "", "abc", "def", "ghi", "jkl", "mno", "pqrs", "tuv", "wxyz"};

    public java.util.List<String> letterCombinations(String digits) {
        java.util.List<String> result = new java.util.ArrayList<>();
        if (digits.isEmpty()) return result;
        backtrack(digits, 0, new StringBuilder(), result);
        return result;
    }

    private void backtrack(String digits, int index, StringBuilder current, java.util.List<String> result) {
        if (index == digits.length()) {
            result.add(current.toString());
            return;
        }
        String letters = mapping[digits.charAt(index) - '0'];
        for (char letter : letters.toCharArray()) {
            current.append(letter);
            backtrack(digits, index + 1, current, result);
            current.deleteCharAt(current.length() - 1);
        }
    }
}

class Solution {
    public java.util.List<String> generateParenthesis(int n) {
        java.util.List<String> result = new java.util.ArrayList<>();
        generateAll(new char[2 * n], 0, result);
        return result;
    }

    private void generateAll(char[] current, int pos, java.util.List<String> result) {
        if (pos == current.length) {
            if (isValid(current)) result.add(new String(current));
            return;
        }
        current[pos] = '(';
        generateAll(current, pos + 1, result);
        current[pos] = ')';
        generateAll(current, pos + 1, result);
    }

    private boolean isValid(char[] s) {
        int balance = 0;
        for (char c : s) {
            balance += (c == '(') ? 1 : -1;
            if (balance < 0) return false;
        }
        return balance == 0;
    }
}

class Solution {
    public java.util.List<String> generateParenthesis(int n) {
        java.util.List<String> result = new java.util.ArrayList<>();
        backtrack(n, 0, 0, new StringBuilder(), result);
        return result;
    }

    private void backtrack(int n, int openCount, int closeCount, StringBuilder current, java.util.List<String> result) {
        if (current.length() == 2 * n) {
            result.add(current.toString());
            return;
        }
        if (openCount < n) {
            current.append('(');
            backtrack(n, openCount + 1, closeCount, current, result);
            current.deleteCharAt(current.length() - 1);
        }
        if (closeCount < openCount) {
            current.append(')');
            backtrack(n, openCount, closeCount + 1, current, result);
            current.deleteCharAt(current.length() - 1);
        }
    }
}

class Solution {
    public boolean exist(char[][] board, String word) {
        int m = board.length, n = board[0].length;
        boolean[][] visited = new boolean[m][n];

        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                if (search(board, word, 0, i, j, visited)) return true;
            }
        }
        return false;
    }

    private boolean search(char[][] board, String word, int index, int row, int col, boolean[][] visited) {
        if (index == word.length()) return true;
        if (row < 0 || row >= board.length || col < 0 || col >= board[0].length) return false;
        if (visited[row][col] || board[row][col] != word.charAt(index)) return false;

        visited[row][col] = true;
        boolean found = search(board, word, index + 1, row + 1, col, visited)
                     || search(board, word, index + 1, row - 1, col, visited)
                     || search(board, word, index + 1, row, col + 1, visited)
                     || search(board, word, index + 1, row, col - 1, visited);
        visited[row][col] = false;
        return found;
    }
}

class Solution {
    public boolean exist(char[][] board, String word) {
        int m = board.length, n = board[0].length;
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                if (search(board, word, 0, i, j)) return true;
            }
        }
        return false;
    }

    private boolean search(char[][] board, String word, int index, int row, int col) {
        if (index == word.length()) return true;
        if (row < 0 || row >= board.length || col < 0 || col >= board[0].length) return false;
        if (board[row][col] != word.charAt(index)) return false;

        char temp = board[row][col];
        board[row][col] = '#'; // mark visited in place

        boolean found = search(board, word, index + 1, row + 1, col)
                     || search(board, word, index + 1, row - 1, col)
                     || search(board, word, index + 1, row, col + 1)
                     || search(board, word, index + 1, row, col - 1);

        board[row][col] = temp; // restore
        return found;
    }
}

class Solution {
    public java.util.List<java.util.List<String>> solveNQueens(int n) {
        java.util.List<java.util.List<String>> result = new java.util.ArrayList<>();
        int[] queens = new int[n]; // queens[row] = column
        backtrack(n, 0, queens, result);
        return result;
    }

    private void backtrack(int n, int row, int[] queens, java.util.List<java.util.List<String>> result) {
        if (row == n) {
            result.add(buildBoard(n, queens));
            return;
        }
        for (int col = 0; col < n; col++) {
            if (isSafe(queens, row, col)) {
                queens[row] = col;
                backtrack(n, row + 1, queens, result);
            }
        }
    }

    private boolean isSafe(int[] queens, int row, int col) {
        for (int r = 0; r < row; r++) {
            int c = queens[r];
            if (c == col || Math.abs(c - col) == Math.abs(r - row)) return false;
        }
        return true;
    }

    private java.util.List<String> buildBoard(int n, int[] queens) {
        java.util.List<String> board = new java.util.ArrayList<>();
        for (int row = 0; row < n; row++) {
            StringBuilder sb = new StringBuilder();
            for (int col = 0; col < n; col++) {
                sb.append(col == queens[row] ? 'Q' : '.');
            }
            board.add(sb.toString());
        }
        return board;
    }
}

class Solution {
    public java.util.List<java.util.List<String>> solveNQueens(int n) {
        java.util.List<java.util.List<String>> result = new java.util.ArrayList<>();
        int[] queens = new int[n];
        boolean[] cols = new boolean[n];
        boolean[] diag1 = new boolean[2 * n]; // row + col
        boolean[] diag2 = new boolean[2 * n]; // row - col + n
        backtrack(n, 0, queens, cols, diag1, diag2, result);
        return result;
    }

    private void backtrack(int n, int row, int[] queens, boolean[] cols, boolean[] diag1, boolean[] diag2, java.util.List<java.util.List<String>> result) {
        if (row == n) {
            result.add(buildBoard(n, queens));
            return;
        }
        for (int col = 0; col < n; col++) {
            int d1 = row + col, d2 = row - col + n;
            if (cols[col] || diag1[d1] || diag2[d2]) continue;

            queens[row] = col;
            cols[col] = diag1[d1] = diag2[d2] = true;

            backtrack(n, row + 1, queens, cols, diag1, diag2, result);

            cols[col] = diag1[d1] = diag2[d2] = false;
        }
    }

    private java.util.List<String> buildBoard(int n, int[] queens) {
        java.util.List<String> board = new java.util.ArrayList<>();
        for (int row = 0; row < n; row++) {
            StringBuilder sb = new StringBuilder();
            for (int col = 0; col < n; col++) {
                sb.append(col == queens[row] ? 'Q' : '.');
            }
            board.add(sb.toString());
        }
        return board;
    }
}

class Solution {
    public void solveSudoku(char[][] board) {
        solve(board);
    }

    private boolean solve(char[][] board) {
        for (int row = 0; row < 9; row++) {
            for (int col = 0; col < 9; col++) {
                if (board[row][col] == '.') {
                    for (char digit = '1'; digit <= '9'; digit++) {
                        if (isValid(board, row, col, digit)) {
                            board[row][col] = digit;
                            if (solve(board)) return true;
                            board[row][col] = '.'; // undo
                        }
                    }
                    return false; // no digit works here -- backtrack further up
                }
            }
        }
        return true; // no empty cells left -- solved
    }

    private boolean isValid(char[][] board, int row, int col, char digit) {
        for (int i = 0; i < 9; i++) {
            if (board[row][i] == digit) return false;
            if (board[i][col] == digit) return false;
            int boxRow = 3 * (row / 3) + i / 3;
            int boxCol = 3 * (col / 3) + i % 3;
            if (board[boxRow][boxCol] == digit) return false;
        }
        return true;
    }
}

class Solution {
    public void solveSudoku(char[][] board) {
        solve(board);
    }

    private boolean solve(char[][] board) {
        for (int row = 0; row < 9; row++) {
            for (int col = 0; col < 9; col++) {
                if (board[row][col] == '.') {
                    for (char digit = '1'; digit <= '9'; digit++) {
                        if (isValid(board, row, col, digit)) {
                            board[row][col] = digit;
                            if (solve(board)) return true;
                            board[row][col] = '.';
                        }
                    }
                    return false;
                }
            }
        }
        return true;
    }

    private boolean isValid(char[][] board, int row, int col, char digit) {
        for (int i = 0; i < 9; i++) {
            if (board[row][i] == digit) return false;
            if (board[i][col] == digit) return false;
            int boxRow = 3 * (row / 3) + i / 3;
            int boxCol = 3 * (col / 3) + i % 3;
            if (board[boxRow][boxCol] == digit) return false;
        }
        return true;
    }
}

